{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting the Shipment aggregate root boundary, all downstream consumers, 2 million rows of production data, and external partner API contracts.",
    "bounded_context": "Shipment Management / Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "The aggregate root representing a single consignment of goods moving from origin to destination(s). Previously assumed a single delivery endpoint; now may represent delivery to multiple endpoints." },
      { "term": "Recipient", "definition": "A party receiving a delivery, identified by name, address, and phone number. Formerly embedded in Shipment as a value object; must now become a first-class collection member with its own delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-level configuration governing how and when delivery should occur (e.g., time windows, safe place instructions, signature requirements, alternate contact). NEW concept introduced by this change." },
      { "term": "Primary Recipient", "definition": "PROPOSED: The designated main recipient on a multi-recipient shipment, used for backward compatibility and as the default for systems that cannot handle multiple recipients." },
      { "term": "Shipment Leg", "definition": "PROPOSED: A segment of a multi-recipient shipment's route, representing the delivery to a single recipient. May or may not map to separate physical movements depending on routing strategy." },
      { "term": "Partner API Contract", "definition": "The agreed data format and semantics exchanged with external partners who consume shipment data. Currently assumes 1:1 Shipment:Recipient." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient. Zero-recipient shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A shipment with no recipient is physically meaningless — there is no destination to deliver to. This is a domain integrity constraint.",
      "testable_assertion": "Any attempt to create or update a Shipment resulting in zero Recipients MUST be rejected with a validation error."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment MUST have a name, address, and phone number. These are required fields.",
      "invariant": true,
      "invariant_justification": "Without address, delivery is impossible. Without name and phone, the courier cannot identify or contact the recipient. This is a physical/operational constraint.",
      "testable_assertion": "Creating a Recipient with a null or empty name, address, or phone number MUST be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a single Shipment MUST have a unique address. Duplicate addresses on the same Shipment are disallowed.",
      "invariant": true,
      "invariant_justification": "Two recipients at the same address on the same shipment is logically a single delivery stop. Allowing duplicates corrupts routing, pricing, and delivery confirmation data.",
      "testable_assertion": "Adding a Recipient whose address matches an existing Recipient on the same Shipment MUST be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Delivery Preferences are optional per Recipient and default to standard delivery if not specified.",
      "invariant": false,
      "invariant_justification": "Default delivery preferences are a business policy. The specific defaults and available options may change over time.",
      "testable_assertion": "A Recipient created without explicit delivery preferences MUST be assigned standard/default delivery preferences."
    },
    {
      "id": "BR-5",
      "rule": "All 2 million existing single-recipient Shipments MUST remain valid and queryable after migration. The migration MUST NOT alter the semantic meaning of existing data.",
      "invariant": true,
      "invariant_justification": "Data loss or corruption of production records violates system integrity and potentially regulatory/contractual obligations.",
      "testable_assertion": "After migration, querying any pre-existing Shipment MUST return exactly the same Recipient data (name, address, phone) as before migration. Recipient count for migrated records MUST equal 1."
    },
    {
      "id": "BR-6",
      "rule": "External partner APIs MUST continue to receive shipment data in the current single-recipient format for existing integrations until partners have migrated.",
      "invariant": false,
      "invariant_justification": "This is a contractual/compatibility policy. Partners can be migrated over time, making this a temporary business constraint rather than a permanent invariant.",
      "testable_assertion": "For any partner API still on the v1 contract, the API response MUST serialize only the primary recipient. No array structure or additional recipients may leak into the v1 payload."
    },
    {
      "id": "BR-7",
      "rule": "For multi-recipient shipments exposed to v1 partner APIs, the first/primary Recipient MUST be used as the single recipient in the serialized payload.",
      "invariant": false,
      "invariant_justification": "The choice of which recipient to surface in backward-compatible mode is a business policy decision, not a physical constraint.",
      "testable_assertion": "When a multi-recipient Shipment is serialized for a v1 partner, the output MUST contain exactly the primary Recipient's name, address, and phone — no other recipients."
    },
    {
      "id": "BR-8",
      "rule": "A Shipment's delivery status MUST be tracked per Recipient, not globally, once multiple recipients exist.",
      "invariant": true,
      "invariant_justification": "A Shipment delivered to Recipient A but not yet to Recipient B cannot be marked as globally 'delivered' without corrupting delivery state. Per-recipient tracking preserves data integrity.",
      "testable_assertion": "Each Recipient on a Shipment MUST have an independent delivery status. The Shipment-level status MUST be a derived aggregate (e.g., 'partially_delivered', 'fully_delivered')."
    },
    {
      "id": "BR-9",
      "rule": "Pricing and billing MUST account for each Recipient as a distinct delivery stop.",
      "invariant": false,
      "invariant_justification": "Pricing models are business policy. Whether multi-recipient is priced per-stop, per-shipment, or via a surcharge is a commercial decision.",
      "testable_assertion": "A Shipment with N recipients MUST generate a pricing calculation that considers N delivery stops. The exact pricing formula is configurable."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator specifies two or more Recipients with valid name, address, phone, and optional delivery preferences",
      "then": "The Shipment is created with all Recipients persisted and individually addressable"
    },
    {
      "id": "AC-2",
      "given": "A new Shipment is being created",
      "when": "The creator specifies zero Recipients",
      "then": "The system rejects the creation with a validation error indicating at least one Recipient is required"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment created before the migration",
      "when": "The Shipment is queried via the API",
      "then": "It returns exactly one Recipient with the original name, address, and phone number, now as element [0] of the recipients collection"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment exists with 3 Recipients",
      "when": "An external partner on the v1 API contract requests this Shipment",
      "then": "The response contains the primary Recipient only, in the original single-recipient payload format, with no breaking schema changes"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment where Recipient A has been delivered but Recipient B has not",
      "when": "The Shipment status is queried",
      "then": "The Shipment shows status 'partially_delivered', Recipient A shows 'delivered', and Recipient B shows 'pending'"
    },
    {
      "id": "AC-6",
      "given": "A Recipient is added to a Shipment",
      "when": "The new Recipient's address matches an existing Recipient's address on that Shipment",
      "then": "The system rejects the addition with a duplicate address error"
    },
    {
      "id": "AC-7",
      "given": "A Recipient on a Shipment has no explicit delivery preferences set",
      "when": "The delivery is dispatched",
      "then": "Standard/default delivery preferences are applied for that Recipient"
    },
    {
      "id": "AC-8",
      "given": "The data migration has completed for the 2M existing shipments",
      "when": "A count query is run on all shipments",
      "then": "The total count matches the pre-migration count, and every migrated shipment has exactly one Recipient with delivery preferences set to defaults"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A Shipment has one Recipient who is removed, leaving zero Recipients",
      "expected_behavior": "The system MUST reject the removal. BR-1 invariant prevents zero-recipient state. Either block the removal or require a replacement Recipient in the same operation."
    },
    {
      "scenario": "Two Recipients on the same Shipment have the same phone number but different addresses",
      "expected_behavior": "This is allowed. Phone number uniqueness is NOT a constraint — only address uniqueness within a Shipment is enforced (e.g., sending to a person's home and their office)."
    },
    {
      "scenario": "A partner on v1 API creates a shipment while the platform now supports multi-recipient",
      "expected_behavior": "The v1 API accepts the single-recipient payload and creates a Shipment with one Recipient. No breakage. The new multi-recipient capability is only exposed on v2 API."
    },
    {
      "scenario": "A multi-recipient Shipment is partially delivered and the sender requests cancellation",
      "expected_behavior": "Only undelivered Recipients' legs can be cancelled. Already-delivered Recipients cannot be 'undelivered.' The Shipment enters a mixed state: some delivered, some cancelled."
    },
    {
      "scenario": "Delivery attempt fails for one Recipient but succeeds for others",
      "expected_behavior": "Retry/reroute logic applies per-Recipient. The Shipment is not globally failed. Per-recipient status tracking (BR-8) ensures independent lifecycle."
    },
    {
      "scenario": "A Shipment has 50 Recipients (stress/abuse case)",
      "expected_behavior": "A configurable maximum Recipients-per-Shipment limit should be enforced. The exact limit is a business policy (not an invariant), but a reasonable default prevents routing/pricing explosion."
    },
    {
      "scenario": "External partner receives a webhook/event for a multi-recipient Shipment status change",
      "expected_behavior": "V1 webhook consumers must receive events referencing only the primary Recipient. V2 consumers receive per-Recipient status events. Event schema versioning is critical."
    },
    {
      "scenario": "Migration is run but a Shipment's existing recipient data has null phone (legacy dirty data)",
      "expected_behavior": "Migration must handle dirty data gracefully — either backfill with a sentinel value and flag for review, or quarantine the record. Must NOT silently drop the shipment."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments enable new revenue streams (multi-drop deliveries, gift-to-many, bulk distribution). Pricing model must evolve — per-stop pricing or tiered surcharges. Migration costs are non-trivial: schema changes, API versioning, partner communication, and QA across 2M records. Incorrect migration risks billing disputes on historical shipments.",
    "operational": "Routing algorithms must evolve from single-destination to multi-stop optimization (TSP-variant). Courier dispatch, ETAs, and proof-of-delivery flows become per-Recipient. Operational dashboards and reporting must handle partial delivery states. Driver apps need UI for multi-stop workflows. Support teams need training on new shipment states.",
    "user": "Senders gain flexibility to ship to multiple recipients in one operation. Recipients each get their own delivery preferences and tracking. However, complexity increases — senders must manage multiple delivery statuses. Notification and tracking UX must clearly separate per-Recipient status from overall Shipment status.",
    "risk": "HIGH risk area is backward compatibility with partner APIs — any data leak of multi-recipient structure into v1 payloads could break partner integrations at scale. Data migration of 2M records carries integrity risk. Introduction of 'partially_delivered' state may break existing business logic that assumes binary delivered/not-delivered. Event consumers that assume single-recipient per shipment will misprocess multi-recipient events if not versioned.",
    "stakeholders_affected": [
      { "group": "External API Partners", "impact": "Must not experience any breaking changes on v1. Need clear migration path and timeline to v2. Must be notified well in advance. Highest risk group." },
      { "group": "Couriers/Drivers", "impact": "Multi-stop deliveries change route planning, workload, and proof-of-delivery workflow. Driver apps must support per-recipient delivery confirmation." },
      { "group": "Senders (Customers)", "impact": "New capability to send to multiple recipients. UX must be intuitive. Pricing transparency is critical — no surprise charges for additional stops." },
      { "group": "Recipients", "impact": "Each recipient gets independent delivery preferences and tracking. Positive impact, but notification fatigue risk if poorly managed." },
      { "group": "Customer Support", "impact": "Must handle new shipment states (partially delivered, mixed cancelled/delivered). Tooling and training needed. Inquiry complexity increases." },
      { "group": "Finance/Billing", "impact": "Pricing model changes. Historical shipment data must remain consistent for auditing. New invoicing logic for multi-stop shipments." },
      { "group": "Product/Analytics", "impact": "Reporting must distinguish single vs multi-recipient shipments. KPIs like 'delivery success rate' must be redefined at Recipient level vs Shipment level." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The spec is directionally clear but leaves significant ambiguity in several critical areas: no definition of 'delivery preferences' (what fields? what options?), no guidance on pricing model for multi-recipient, no stated maximum recipients per shipment, no partner migration timeline or strategy, and no clarity on whether a multi-recipient shipment is one physical package split or multiple packages under one logical grouping. These gaps affect multiple business rules and acceptance criteria.",
    "high_confidence_areas": [
      "At-least-one-recipient invariant (BR-1) — physically and logically unambiguous",
      "Backward compatibility requirement for 2M existing records (BR-5)",
      "Need for per-recipient delivery status tracking (BR-8)",
      "Partner API backward compatibility requirement (BR-6)"
    ],
    "low_confidence_areas": [
      "Exact definition and schema of 'delivery preferences' — not specified",
      "Physical model: is a multi-recipient shipment one parcel with multiple stops, or multiple parcels under one logical shipment?",
      "Pricing model for additional recipients",
      "Maximum recipient count per shipment",
      "Primary recipient designation logic — is it explicit or positional?",
      "Event/webhook versioning strategy for partners"
    ],
    "assumptions": [
      "Multi-recipient means multiple delivery destinations (addresses), not multiple people at the same address",
      "Existing single-recipient shipments will be migrated in-place to the new schema (recipients collection with one element), not kept in a legacy format",
      "A 'primary recipient' concept will be introduced for backward compatibility with v1 APIs",
      "Delivery preferences are per-recipient, not per-shipment",
      "The physical logistics model supports multi-stop routes (not just hub-and-spoke)"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'delivery preferences' without defining what preferences are available. This is a new domain concept with no schema. Are we talking about time windows, safe-place instructions, signature requirements, neighbor delivery, or something else entirely? The Recipient entity cannot be modeled correctly without this.",
      "affected_stakeholders": ["Product Team", "Recipients", "Couriers/Drivers", "Engineering"],
      "options": ["A) Define a minimal set (time window, signature required, safe place instructions) and iterate", "B) Make delivery preferences a free-form key-value bag", "C) Wait for full product spec on preferences before implementing"],
      "recommendation": "Option A — define a minimal, typed set of preferences. Free-form bags erode domain integrity. But we need Product to enumerate the initial set."
    },
    {
      "type": "ambiguity",
      "description": "Is a multi-recipient Shipment one physical package making multiple stops, or multiple separate packages grouped under one logical shipment? This fundamentally changes routing, tracking, and proof-of-delivery semantics.",
      "affected_stakeholders": ["Couriers/Drivers", "Operations", "Engineering", "Senders"],
      "options": ["A) Single package, multiple stops (relay model)", "B) Multiple packages, one shipment (split model)", "C) Support both with a shipment type discriminator"],
      "recommendation": "This must be answered by Product and Operations before implementation. The domain model, routing, and billing are all dependent on this answer."
    },
    {
      "type": "missing_context",
      "description": "No maximum recipients-per-shipment limit is specified. Without a bound, routing optimization becomes computationally expensive (TSP complexity), pricing becomes unpredictable, and the system is vulnerable to abuse.",
      "affected_stakeholders": ["Operations", "Engineering", "Finance/Billing"],
      "options": ["A) Set a hard limit (e.g., 10 recipients max)", "B) Set a soft limit with override capability for enterprise customers", "C) No limit, handle dynamically"],
      "recommendation": "Option B — soft limit of 10 with enterprise override. Prevents abuse while allowing flexibility for known use cases."
    },
    {
      "type": "missing_context",
      "description": "No partner migration strategy or timeline provided. We know partners must not break on v1, but there is no guidance on v2 API rollout, partner communication plan, or deprecation timeline for v1.",
      "affected_stakeholders": ["External API Partners", "Product Team", "Engineering"],
      "options": ["A) Ship v2 alongside v1, deprecate v1 after 12 months", "B) Extend v1 with optional multi-recipient fields (non-breaking)", "C) Wait for partner readiness assessment before designing v2"],
      "recommendation": "Option A with a formal deprecation schedule. But we need Partnership/BD team input on partner readiness and contractual obligations."
    }
  ],

  "rejection_reasons": []
}

